// Enhanced privacy with shielded pool integration
import {
  ZkiraClient,
  ShieldedPoolClient
} from '@zkira/sdk'

// Initialize clients
const client = new ZkiraClient()
const shieldedPool = new ShieldedPoolClient()

// Derive stealth address from recipient's meta-address
const { stealthAddress, ephemeralPubkey } =
  client.deriveStealthAddress(recipientMetaAddress)

// For maximum privacy, deposit to shielded pool first
const depositProof = await shieldedPool.deposit({
  amount: 1000000, // Fixed denomination
  token: 'USDC'
})

// Later, withdraw privately to stealth address
const withdrawProof = await shieldedPool.withdraw({
  to: stealthAddress,
  nullifierHash: depositProof.nullifierHash,
  proof: depositProof.zkProof
})
